import{_ as i,o as n,c as a,ai as t}from"./chunks/framework.C4ntERNc.js";const u=JSON.parse('{"title":"Core Concepts","description":"","frontmatter":{"title":"Core Concepts","lang":"en-US","layout":"doc","outline":"deep"},"headers":[],"relativePath":"reference-manual/formal-reference/core-concepts.md","filePath":"reference-manual/formal-reference/core-concepts.md"}'),o={name:"reference-manual/formal-reference/core-concepts.md"};function s(l,e,r,c,d,p){return n(),a("div",null,[...e[0]||(e[0]=[t(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /jz-hdl/reference-manual/formal-reference/core-concepts.md for this page in Markdown format</div><h1 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to “Core Concepts”">​</a></h1><h2 id="identifiers" tabindex="-1">Identifiers <a class="header-anchor" href="#identifiers" aria-label="Permalink to “Identifiers”">​</a></h2><p><strong>Syntax:</strong> <code>(?!^_$)^[A-Za-z_][A-Za-z0-9_]{0,254}$</code></p><ul><li>ASCII letters, digits, underscore</li><li>Max length 255; case-sensitive</li><li>Single underscore <code>_</code> is reserved for module instantiation no-connect only</li><li>Keywords (uppercase, reserved): <ul><li>Project: <code>CLOCKS</code>, <code>IN_PINS</code>, <code>OUT_PINS</code>, <code>INOUT_PINS</code>, <code>MAP</code>, <code>CLOCK_GEN</code>, <code>BUS</code></li><li>Flow Control: <code>IF</code>, <code>ELIF</code>, <code>ELSE</code>, <code>SELECT</code>, <code>CASE</code>, <code>DEFAULT</code>, <code>MUX</code></li><li>Config / Parameters: <code>CONFIG</code>, <code>CONST</code>, <code>OVERRIDE</code></li><li>Connections: <code>PORT</code>, <code>IN</code>, <code>OUT</code>, <code>INOUT</code>, <code>WIRE</code>, <code>SOURCE</code>, <code>TARGET</code></li><li>Storage: <code>REGISTER</code>, <code>LATCH</code>, <code>MEM</code></li><li>Logic Type: <code>ASYNCHRONOUS</code>, <code>SYNCHRONOUS</code></li><li>Clock Domains: <code>CDC</code></li></ul></li><li>Identifiers (uppercase, reserved): <ul><li>Clock Types: <code>PLL</code>, <code>DLL</code>, <code>CLKDIV</code></li><li>Clock Domain Crossing Types: <code>BIT</code>, <code>BUS</code>, <code>FIFO</code>, <code>HANDSHAKE</code>, <code>PULSE</code>, <code>MCP</code>, <code>RAW</code></li><li>Memory Types: <code>BLOCK</code>, <code>DISTRIBUTED</code></li><li>Memory Ports: <code>ASYNC</code>, <code>SYNC</code>, <code>WRITE_FIRST</code>, <code>READ_FIRST</code>, <code>NO_CHANGE</code></li><li>Template / Array: <code>IDX</code></li><li>Semantic Drivers: <code>VCC</code>, <code>GND</code></li></ul></li><li>Directives (prefixed with <code>@</code>, structural): <ul><li><code>@project</code> / <code>@endproj</code>: Project definition including board connections, clocks and the top module <ul><li><code>@import</code>: Import external modules, blackboxes, globals into a project</li><li><code>@blackbox</code>: Declare an opaque (blackbox) module inside a project</li><li><code>@top</code>: Set the top level module or blackbox for the project</li></ul></li><li><code>@module</code> / <code>@endmod</code>: A single hardware definition <ul><li><code>@new</code>: Instantiate module or blackbox</li><li><code>@check</code>: Compile-time assertion</li><li><code>@feature</code> / <code>@else</code> / <code>@endfeat</code>: Conditional feature guard block</li><li><code>@template</code> / <code>@endtemplate</code>: Template definition for reusable logic <ul><li><code>@scratch</code>: Declare a scratch wire inside a template body</li></ul></li><li><code>@apply</code>: Expand a template at the callsite</li><li><code>@file</code>: File-level directive for memory content initialization</li></ul></li><li><code>@global</code> / <code>@endglob</code>: Global constants</li></ul></li></ul><h2 id="comments" tabindex="-1">Comments <a class="header-anchor" href="#comments" aria-label="Permalink to “Comments”">​</a></h2><ul><li>Line: <code>//</code> to end of line</li><li>Block: <code>/* ... */</code> (no nesting)</li><li>Comments may appear between tokens, not inside tokens</li></ul><h2 id="fundamental-terms" tabindex="-1">Fundamental terms <a class="header-anchor" href="#fundamental-terms" aria-label="Permalink to “Fundamental terms”">​</a></h2><ul><li><strong>Signal:</strong> A declared identifier representing a hardware object (PORT, WIRE, REGISTER, LATCH, MEM port, or BUS signal). A signal has a declared width and static type. Signals are syntax-level objects that appear in source declarations.</li><li><strong>Net:</strong> The resolved electrical connectivity resulting from aliasing and directional connections between signals after elaboration. A net may connect multiple signals but represents a single driven value per bit. After all assignments and aliases are resolved, each net must have zero or one active driver within any single execution path, unless it is a tri-state net where all but one driver assigns <code>z</code> for each bit.</li><li><strong>Deterministic net:</strong> A net that, for every execution path, has exactly one active driver per bit (or is resolved via valid tri-state rules). Any deviation is a compile-time error.</li><li><strong>Driver:</strong> Any signal or construct that can contribute a value to a net in a given execution path. Examples: REGISTER current-value output, LATCH output, OUT/INOUT port when assigned, WIRE with a directional assignment, constant literal in a directional assignment, semantic drivers (GND, VCC).</li><li><strong>Active driver:</strong> A driver that contributes a determinate logic value (<code>0</code> or <code>1</code>) to a net in a given execution path. A driver assigning <code>z</code> is not active and does not participate in active-driver counting. A driver whose value contains <code>x</code> is active but produces an x-dependent net.</li><li><strong>Sink:</strong> Any signal position that receives a value from a driver in a given assignment context (e.g., module input, register next-state input, intermediate targets). A signal may act as a driver in one context and a sink in another.</li><li><strong>Observable sink:</strong> A signal location whose value is architecturally visible or externally observable. Includes: REGISTER next-state and reset values, MEM initialization contents, OUT/INOUT ports, and top-level project pins.</li><li><strong>Execution path:</strong> A statically distinct control-flow branch through a block, defined by mutually exclusive IF/ELIF/ELSE or SELECT/CASE structures. Execution paths are determined structurally, not by symbolic reasoning. Independent control-flow chains at the same nesting level are treated as potentially concurrent.</li><li><strong>Assignable identifier:</strong> A signal that may legally appear on the left-hand side of an assignment. Includes REGISTER (in SYNCHRONOUS only), WIRE, OUT port, INOUT port, LATCH (guarded, in ASYNCHRONOUS only), and writable BUS signals.</li><li><strong>Register:</strong> A storage signal bound to a clock domain (flip-flops) that exposes a read-only current-value output readable in all blocks (acts as a driver) and a write-only next-state input assignable only in its home SYNCHRONOUS block (acts as a sink). Has a mandatory reset value defined at declaration.</li><li><strong>Latch:</strong> A level-sensitive storage signal updated via guarded assignments in ASYNCHRONOUS blocks. A latch exposes a continuously readable stored value and does not belong to a clock domain.</li><li><strong>Home domain:</strong> The clock domain in which a REGISTER is defined and may be legally assigned. A register may only be written in its home domain and may not be observed in other domains without an explicit CDC bridge.</li></ul><h2 id="observability-rule-x-handling" tabindex="-1">Observability rule (x handling) <a class="header-anchor" href="#observability-rule-x-handling" aria-label="Permalink to “Observability rule (x handling)”">​</a></h2><p>Values containing any <code>x</code> bits may only be used if all such bits are provably masked before reaching an observable sink. If an <code>x</code> bit can reach any observable sink, compilation fails. Masking is structural, not algebraic — the compiler does not assume logical identities (e.g., <code>x &amp; 0 = 0</code>) as masking unless the bit is structurally removed. The unused branch of a ternary (<code>? :</code>) is considered structurally masked only if the condition is provably constant at compile time; if the condition is runtime-dependent, both branches must independently satisfy the observability rule.</p><h2 id="exclusive-assignment-rule" tabindex="-1">Exclusive Assignment Rule <a class="header-anchor" href="#exclusive-assignment-rule" aria-label="Permalink to “Exclusive Assignment Rule”">​</a></h2><p>For any assignable identifier (REGISTER, WIRE, OUT, INOUT), every execution path through a block must contain zero or one assignment to every bit of that identifier.</p><p>Path-exclusive determinism (PED) rules:</p><ol><li>Independent IF/SELECT chains at the same nesting level may not assign to the same bits.</li><li>A root-level assignment followed by a nested assignment to the same bits is a compile error.</li><li>Assignments in branches of a single IF/ELIF/ELSE or SELECT/CASE tree are mutually exclusive and allowed.</li></ol><p>Zero-assignment paths:</p><ul><li>Registers hold their current value (clock gating semantics).</li><li>Wires/ports are undriven (possible floating net error if read).</li></ul><p><strong>Note:</strong> If you want a net to be driven in only some, but not all, execution paths, you must assign the net with High-Impedance (<code>z</code>) in the undriven paths.</p><h2 id="high-impedance-and-tri-state-logic" tabindex="-1">High-impedance and tri-state logic <a class="header-anchor" href="#high-impedance-and-tri-state-logic" aria-label="Permalink to “High-impedance and tri-state logic”">​</a></h2><p>High-impedance (<code>z</code>) represents the absence of a driven value on a net or port. A driver that assigns <code>z</code> is considered electrically disconnected and does not contribute an active logic value.</p><p><strong>Literal form:</strong></p><ul><li><code>z</code> is permitted only in binary literals. <code>z</code> is not permitted in decimal or hexadecimal literals.</li><li>When the MSB is <code>z</code>, extension pads with <code>z</code>.</li></ul><p><strong>Active vs. high-impedance drivers:</strong></p><ul><li>An active driver supplies a determinate <code>0</code> or <code>1</code>; a driver supplying <code>z</code> is not active.</li><li>A net may have multiple drivers only if, for every execution path, at most one driver supplies a non-<code>z</code> value.</li></ul><p><strong>Tri-state net semantics:</strong></p><ul><li>Exactly one active driver must be present in each execution path; all others (if any) assign <code>z</code>.</li><li>If all drivers assign <code>z</code> on an execution path and the net is read, this is a compile-time error (floating net).</li></ul><p><strong>Tri-state ports:</strong></p><ul><li>OUT ports may assign <code>z</code> to release the port.</li><li>INOUT ports may assign <code>z</code> to release the port and may be read when released.</li></ul><p><strong>Registers and latches:</strong></p><ul><li>Registers and latches cannot store or produce <code>z</code>.</li><li>Register reset literals must not contain <code>x</code> or <code>z</code>.</li><li>To implement tri-state behavior, assign <code>z</code> to a port, not to a register.</li></ul><p><strong>Examples:</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>// Valid:</span></span>
<span class="line"><span>out_port &lt;= enable ? data : 8&#39;bzzzz_zzzz;</span></span>
<span class="line"><span>inout_port &lt;= wr_en ? data : 8&#39;bzzzz_zzzz;</span></span>
<span class="line"><span>IF (!wr_en) { register &lt;= inout_port; }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Invalid (compile error — reading a floating net):</span></span>
<span class="line"><span>// All drivers assign z to the net:</span></span>
<span class="line"><span>// register &lt;= floating_net;</span><span>   // ERROR</span></span></code></pre></div><h2 id="bit-slicing-and-indexing" tabindex="-1">Bit slicing and indexing <a class="header-anchor" href="#bit-slicing-and-indexing" aria-label="Permalink to “Bit slicing and indexing”">​</a></h2><p><strong>Syntax:</strong> <code>signal[MSB:LSB]</code></p><ul><li>MSB and LSB are nonnegative integers or <code>CONST</code> names</li><li><code>MSB &gt;= LSB</code> is required</li><li>Indices are inclusive; width = MSB - LSB + 1</li><li>Indices must be within declared width</li></ul><p><strong>Examples:</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>data[7:0]        // lower byte of &#39;data&#39;</span></span>
<span class="line"><span>data[15:8]       // upper byte of a 16-bit &#39;data&#39;</span></span>
<span class="line"><span>data[XLEN-1:0]   // CONST-based slice</span></span>
<span class="line"><span>data[0:0]        // single bit (width 1)</span></span></code></pre></div><h2 id="concatenation" tabindex="-1">Concatenation <a class="header-anchor" href="#concatenation" aria-label="Permalink to “Concatenation”">​</a></h2><p><strong>Syntax:</strong> <code>{a, b, c}</code></p><ul><li>MSB-first ordering: <code>a</code> is the most-significant portion</li><li>Width = sum of all element widths</li><li>Can be used on LHS for decomposition</li></ul><h2 id="design-hierarchy" tabindex="-1">Design hierarchy <a class="header-anchor" href="#design-hierarchy" aria-label="Permalink to “Design hierarchy”">​</a></h2><ul><li><strong>@project</strong> is the top-level integration point (one per design unit).</li><li><strong>@module</strong> defines reusable hardware blocks with ports, logic, and state.</li><li><strong>@new</strong> instantiates child modules inside parent modules.</li><li><strong>@blackbox</strong> provides opaque interfaces for external IP.</li><li><strong>@global</strong> provides cross-module sized literal constants.</li><li><strong>@template</strong> defines compile-time reusable logic blocks that expand inline via <code>@apply</code>.</li><li><strong>@feature</strong> conditionally includes/excludes declarations and logic.</li><li><strong>@check</strong> validates compile-time invariants.</li></ul>`,42)])])}const h=i(o,[["render",s]]);export{u as __pageData,h as default};
